type ServiceIdentifier<T> = symbol & { __type?: T }

type Resolver = <T>(id: ServiceIdentifier<T>) => T

interface UserRepository {
  /** Find a user by id. */
  findById(id: string): Promise<{ id: string; name: string }>
}

interface UserService {
  getUser(id: string): Promise<{ id: string; name: string }>
}

interface Container {
  register<T>(
    id: ServiceIdentifier<T>,
    setup: { useFactory(context: { resolve: Resolver }): T }
  ): void
  resolve<T>(id: ServiceIdentifier<T>): T
}

declare const createContainer: () => Container

const IUserRepository = Symbol('IUserRepository') as ServiceIdentifier<UserRepository>
const IUserService = Symbol('IUserService') as ServiceIdentifier<UserService>

const container = createContainer()
container.register(IUserService, {
  useFactory: ({ resolve }) => ({
    getUser(id) {
      return resolve(IUserRepository).findById(id)
    },
  }),
})

const userService = container.resolve(IUserService)

story-container:
type ServiceIdentifier<T> = symbol & { __type?: T }

interface Clock {
  /** Returns the current wall-clock time. */
  now(): Date
}

interface Container {
  register<T>(id: ServiceIdentifier<T>, setup: { useValue: T }): void
  resolve<T>(id: ServiceIdentifier<T>): T
}

declare const createContainer: () => Container

const IClock = Symbol('IClock') as ServiceIdentifier<Clock>
const container = createContainer()
container.register(IClock, {
  useValue: { now: () => new Date() },
})

const clock = container.resolve(IClock)
clock.now()

