story-lifecycle:
enum LifecycleEnum {
  transient = 'transient',
  singleton = 'singleton',
  resolution = 'resolution',
}

type ServiceIdentifier<T> = symbol & { __type?: T }

interface Cache {
  get(key: string): string | undefined
}

interface Container {
  register<T>(
    id: ServiceIdentifier<T>,
    setup: { lifecycle: LifecycleEnum; useValue: T }
  ): void
}

declare const createContainer: () => Container

const ICache = Symbol('ICache') as ServiceIdentifier<Cache>
const container = createContainer()
container.register(ICache, {
  lifecycle: LifecycleEnum.singleton,
  useValue: { get: () => 'hit' },
})

story-refs:
type ServiceIdentifier<T> = symbol & { __type?: T }

type Ref<T> = { current: T }

interface ServiceA {
  run(): void
}

interface Container {
  resolve<T>(
    id: ServiceIdentifier<T>,
    options: { ref: true }
  ): Ref<T>
}

declare const createContainer: () => Container

const IServiceA = Symbol('IServiceA') as ServiceIdentifier<ServiceA>
const container = createContainer()
const serviceARef = container.resolve(IServiceA, { ref: true })
serviceARef.current.run()

